import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as i,e as a}from"./app-d96c843a.js";const t={},e=a(`<h1 id="面试-springboot" tabindex="-1"><a class="header-anchor" href="#面试-springboot" aria-hidden="true">#</a> 面试-SpringBoot</h1><h3 id="说一下springboot" tabindex="-1"><a class="header-anchor" href="#说一下springboot" aria-hidden="true">#</a> 说一下SpringBoot</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：说一下SpringBoot</b></summary><p><b style="color:#f19977;">答：SpringBoot一个重要的思想是约定大于配置，其整合了所有的后端框架。优点有能快速创建独立运行的Spring项目以及与主流框架集成。大量的自动配置，简化开发。无需配置大量的XML文件，开箱即用。</b></p></details><h3 id="springboot自动配置原理" tabindex="-1"><a class="header-anchor" href="#springboot自动配置原理" aria-hidden="true">#</a> SpringBoot自动配置原理</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：SpringBoot自动配置原理</b></summary><p><b style="color:#f19977;">答：在SpringBoot项目中的启动类上有一个@SpringBootApplication注解，其是一个复合注解包含@SpringBootConfiguration、@EnableAutoConfiguration、@ComponentScan。<br>1. @SpringBootConfiguration：表示其是一个配置类<br>2. @EnableAutoConfiguration：是实现自动化配置的核心注解，该注解通过@Import导入对应的配置选择器，内部就是读取了该项目所有Jar包的classpath路径下的META-INF/spring.factories文件中的所配置类的全类名，在这些配置类中所定义的Bean会根据条件注解@ConditionalOnClass所指定的条件来决定是否需要将其放入Spring容器中。<br>3. @ComponentScan：配置包扫描，默认就是启动类所在包及其子包</b></p></details><h3 id="springboot中常用注解" tabindex="-1"><a class="header-anchor" href="#springboot中常用注解" aria-hidden="true">#</a> SpringBoot中常用注解</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：SpringBoot中常用注解</b></summary><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>@SpringBootConfiguration
@EnableAutoConfiguration
@ComponentScan
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details>`,7),r=[e];function s(l,d){return n(),i("div",null,r)}const b=o(t,[["render",s],["__file","面试-SpringBoot.html.vue"]]);export{b as default};
